import React, { useContext } from 'react'
import { Smart } from "../components/data/Smart";
import { Nout } from '../components/data/Nout';
import { UserContext } from "../components/User";
import { Bicy } from '../components/data/Bicy';
import { Link } from 'react-router-dom'

function Catalog() {
    const User = useContext(UserContext);
    const handleKorzina = (id) => {
        if (User.user) {
            if (User.user.korzina) {
                if (!User.user.korzina.includes(id)) {
                    User.setUser({ ...User.user, korzina: [...User.user.korzina, id] });
                }
            }
        } else {
            User.setUser({ ...User.user, korzina: [id] });
        }
    };
    return (
        <div className="Catalog">
            
             <ul class="lightrope">
                <li></li><li></li><li></li><li></li><li></li><li></li>
            </ul>
            <div className="Name">
               <h2>Смартфоны</h2> 
            </div>
            {Smart.map(element => (
                <div key={element.id} className="Catalog__card">
                    <img src={element.img} alt={element.title} />
                  <Link to={"p/" + element.id}><h1>{element.title}</h1> </Link>
                    <div className="Meet">
                        <p>{element.cost}</p>
                    </div>
                    <button className="Catalog__Add" onClick={() => handleKorzina(element.id)}>
                        Добавить в избранную
                    </button>
                </div>
            ))}
            <div className="Nout">
                Ноутбуки
            </div>
            {Nout.map(element => (
                <div key={element.id} className="Catalog__card">
                    <img src={element.img} alt={element.title} />
                    <Link to={"p/" + element.id}><h1>{element.title}</h1> </Link>
                    <div className="Meet">
                        <p>{element.cost}</p>
                    </div>
                    <button className="Catalog__Add" onClick={() => handleKorzina(element.id)}>
                        Добавить в избранную
                    </button>
                </div>
                ))}
            <div className="Byc">
                Велосипеды
            </div>
            {Bicy.map(element => (
                <div key={element.id} className="Catalog__card">
                    <img src={element.img} alt={element.title} />
                    <Link to={"p/" + element.id}><h1>{element.title}</h1> </Link>
                    <div className="Meet">
                        <p>{element.cost}</p>
                    </div>
                    <button className="Catalog__Add" onClick={() => handleKorzina(element.id)}>
                        Добавить в избранную
                    </button>
                </div>
                ))}
        </div>
    );
}

export default Catalog;
